   return nullptr;
 }
+static Value *simplifyAndOrOfFCmpsWithConstants(FCmpInst *Cmp0, FCmpInst *Cmp1,
+                                                bool IsAnd) {
+  // Look for this pattern: {and/or} (fcmp X, C0), (fcmp X, C1)).
+  if (Cmp0->getOperand(0) != Cmp1->getOperand(0))
+    return nullptr;
+
+  const APFloat *C0, *C1;
+  if (!match(Cmp0->getOperand(1), m_APFloat(C0)) ||
+      !match(Cmp1->getOperand(1), m_APFloat(C1)))
+    return nullptr;
+
+  // Only handle ordered comparisons (ignore unordered for simplicity).
+  // Also require same predicate.
+  FCmpInst::Predicate Pred0 = Cmp0->getPredicate();
+  FCmpInst::Predicate Pred1 = Cmp1->getPredicate();
+  if (Pred0 != Pred1)
+    return nullptr;
+  if (!FCmpInst::isOrdered(Pred0))
+    return nullptr;
+
+  // Ensure fast-math flags are identical.
+  if (Cmp0->getFastMathFlags() != Cmp1->getFastMathFlags())
+    return nullptr;
+
+  // Determine which constant is "stronger" (i.e., implies the other).
+  // For LT/LE: smaller constant is stronger (X < C0 implies X < C1 if C0 <= C1).
+  // For GT/GE: larger constant is stronger.
+  // For EQ/NE: cannot simplify.
+  APFloat::cmpResult CR = C0->compare(*C1);
+  // If constants are unordered (one is NaN), bail out.
+  if (CR == APFloat::cmpUnordered)
+    return nullptr;
+
+  // Determine which comparison implies the other (i.e., subset).
+  // If CR == cmpLessThan: C0 < C1
+  // If CR == cmpEqual: equal constants.
+  // If CR == cmpGreaterThan: C0 > C1.
+  bool C0Stronger = false;
+  switch (Pred0) {
+  case FCmpInst::FCMP_OLT:
+  case FCmpInst::FCMP_OLE:
+    // Smaller constant is stronger.
+    C0Stronger = (CR == APFloat::cmpLessThan || CR == APFloat::cmpEqual);
+    break;
+  case FCmpInst::FCMP_OGT:
+  case FCmpInst::FCMP_OGE:
+    // Larger constant is stronger.
+    C0Stronger = (CR == APFloat::cmpGreaterThan || CR == APFloat::cmpEqual);
+    break;
+  default:
+    // Cannot simplify.
+    return nullptr;
+  }
+
+  // For AND we want the stronger condition (intersection).
+  // For OR we want the weaker condition (union).
+  // If C0 is stronger, then Cmp0 is stronger.
+  if (IsAnd) {
+    // Return the stronger comparison.
+    return C0Stronger ? Cmp0 : Cmp1;
+  } else {
+    // Return the weaker comparison.
+    return C0Stronger ? Cmp1 : Cmp0;
+  }
+}

 static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                                    FCmpInst *RHS, bool IsAnd) {
@@ -1849,7 +1914,8 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  ? static_cast<Value *>(LHS)
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }
-
+  if (Value *V = simplifyAndOrOfFCmpsWithConstants(LHS, RHS, IsAnd))
+    return V;
   return nullptr;
 }

